/*!40000 ALTER TABLE `communities` DISABLE KEYS */;
INSERT INTO `communities` VALUES (1,'Ayman Sabae','CEO and Health Systems Specialist','storage/574687d635214c85e28fc7918b2e091b.jpg','<p><strong><em>Egypt</em></strong></p><p>A medical doctor with 18 years of experience in healthcare systems management with a Masters\' degree in International Healthcare Systems Management. Ayman is a Right to Health researcher at EIPR and the CEO of the Egyptian social enterprise “Shamseya\".</p>',NULL,NULL,'https://www.linkedin.com/in/sabaeayman/','2023-08-30 10:36:27','2024-05-22 12:05:17','storage/b0fe3d76df0ddba644188ff9104f1460.jpg'),(2,'Chaden Moataz','Projects Manager','storage/c3f72636404239deba19ae4bc6f6e9c1.jpg','<p><strong><em>Egypt</em></strong></p><p>Master\'s degree holder in Political Communication from Paris II Assass University, Paris, I have more than 7 years of experience in the development field with a focus on women\'s empowerment. I\'ve been exposed to education and health with a direct relationship with youth, which gave me the chance to get certified by ICF as a youth life coach. I am a member of the French network Jeuness Med. and a freelance mentor in strategic communication.</p>',NULL,NULL,'https://eg.linkedin.com/in/chaden-moataz-124501124','2023-08-30 10:54:31','2024-05-22 12:05:26','storage/2fc625149a66acf37a85f4ad3e091e54.jpg'),(3,'Maysaa Nemer','Assistant Professor and Director of the Institute of Community and Public Health and the MPH Program','storage/4aa8c3d88e7ea868a23170ba3ab13c67.jpg','<p><strong><em>Palestine</em></strong></p><p>Maysaa Nemer is an Assistant Professor and Director of the Institute of Community and Public Health and the MPH Program at Birzeit University. She holds a PhD in Public Health - Occupational Epidemiology and MPhil in International Community Health from the University of Oslo, Norway.&nbsp;</p><p><br>Her research focuses on a range of public health topics where women and adolescents are the main focus. This includes environmental and occupational health, social and economic aspects of environmental exposures, the effects of environmental and structural factors on working women’s health, gender awareness among healthcare providers, the aspects of data governance and human rights in digital health initiatives for women’s health services, and ethical issues surrounding adolescent health data privacy.</p>','https://twitter.com/MaysaNemer?t=oOcpvKa2eOy8h00UBCUt3g&s=09',NULL,'https://www.linkedin.com/in/maysa-nemer-470a0675/?originalSubdomain=ps','2023-08-30 11:21:05','2024-05-22 12:05:39','storage/d7539881c3e071257ef46713c2bacc9b.jpg'),(4,'Tamam Quran ','Advocacy and Communication Officer','storage/600b975edc400d9d6530b3529be9a701.jpg','<p><strong><em>Palestine</em></strong></p><p>An Educationalist professional with a strong focus on creating culturally relevant and interdisciplinary curricula. As an Advocacy and Communication Consultant at Birzeit University, she successfully coordinated projects related to artificial intelligence, data for development, and digital transformation. Previously, as an IB and MYP English Teacher at Ramallah Friends School, she designed and implemented engaging and culturally responsive English curricula while mentoring students on their final projects. Additionally, she served as a board member and teacher at I Know I Can, where she developed an English language curriculum centered around Palestinian culture and struggle, fostering critical thinking and problem-solving skills.</p>',NULL,NULL,NULL,'2023-08-30 11:54:22','2024-05-22 12:05:53','storage/4b4a46f15fa1facd841261ed1da54c94.jpg'),(5,'Rania Qasim ','Head of Professional Development - CCE','storage/f63904c9c16a1037b4d7b3648ba50ae7.jpg','<p><strong><em>Palestine</em></strong></p><p>Rania Qasim is specialized in training methods and curricula design focusing on adopting different learning innovation approaches in order to enhance the quality of learning at the Palestinian non-formal education system. She has an intensive experience in community development related projects that mainly target women, youth and CBOs. Rania has been leading the conceptualization, design, development and implementation of several professional programs and diplomas) in addition to many training courses in different fields (business, project management, strategic planning, marketing, gender, training of trainers, etc.).&nbsp;</p><p>Rania has been delivering ToT program and providing instructional design support to the subject matter experts and trainers to be able to adopt modern practices in curricula design and development. Rania has a very good experience in adopting the e-learning approaches in training life cycle and providing pedagogical support to the subject matter experts in the e-learning modules design and developed process. Rania led the development and implementation of several project with the government sector, including training and coaching for judges, prosecutors, counsellors and managers.</p>',NULL,NULL,NULL,'2023-08-30 11:57:12','2024-05-22 12:06:04','storage/b89eaa70737e00565c84a9d8a865e31c.jpg'),(6,'Osama Mimi ','Director ','storage/e0244707f610499461201a9cc9f4c90c.jpg','<p><strong><em>Palestine</em></strong></p><p>Dr. Osama Mimi is the founder and the director of the Unit for Learning Innovation (ULI) at CCE, which aims at improving the quality of formal and non-formal education systems in Palestine and the region through adopting learning innovation approaches and “outside-the–box” solutions that can be scaled and sustained. Dr. Osama has been leading the conceptualization, design, fundraising and implementation processes of a wide range of strategic learning innovations projects locally, regionally and internationally. Through the Unit for Learning Innovation, he has engaged in conceptualizing, designing, planning and implementing a wide range of learning innovation projects at school and university levels in addition to non-formal education systems and institutional capacity building projects.&nbsp;</p><p>Dr. Osama has an undergraduate degree in Physics from the University of Jordan, MSc degree in Atomic Physics from the University of Manchester in UK (honor list) and a PhD in Curricula Design and Teaching Methods from the Hebrew University of Jerusalem in Al Quds (honor list).Dr. Osama has an excellent knowledge in the Palestinian and the regional formal(basic and higher education) and non-formal education systems, and has excellent skills in leadership, management, communication, research, evaluation, learning design, curricula review and development, teaching and training skills.</p>',NULL,NULL,NULL,'2023-08-30 12:08:12','2024-05-22 12:06:12','storage/74d484db558998092b29084001803400.jpg'),(7,'Marwan Tarazi','Head of Developmental Insights & Creative Solutions','storage/594d743f523b1d6a9d179b5dff6176ad.jpg','<p><strong><em>Palestine</em></strong></p><p>Marwan Tarazi firmly believes that only through good education can the world become a better and safer place for all. Marwan has dedicated his career to redesigning or creating new educational models necessary to prepare future generations for an extremely fast-changing world and uncertain future. He is specialized in strategy formulation focusing on institutional capacity building that links human resource development with institutional structures, market and employment dynamics and overall sociol-economic environment. Marwan is the architect of several national programs and bodies such as, CAPABILITY (Capacity Building for Educational institutions through Innovation and Technology), a planned knowledge park at Birzeit University, the IT Center of Excellence, Knowledge Consortium, and the Public Administration and Civil Service Capacity Building program at CCE.&nbsp;</p><p>Marwan has an undergraduate degree in Electrical Engineering from McGill University in Canada, and an international MBA degree from the Kellogg’s School of Business at North Western University. Marwan started his career in the US and Canada in the mid-1980s and moved back to Palestine in the early 1990s. He has served as a director for the Computer Center at the University, the director of the Information Technology Unit for four years, the head of the Business Development Unit at CCE for three years, and the director of CCE since August 2007.</p>',NULL,NULL,NULL,'2023-08-30 12:10:26','2024-05-22 12:06:34','storage/dc45883804a9ddcb59bb55aedd32d53e.jpg'),(8,'Rasha Alkhmour','Program Coordinator','storage/07b287136dd2971e9f32538852c4cb9f.jpg','<p><strong><em>Palestine</em></strong></p><p>Rasha holds a Master\'s degree in International Cooperation and Development from Bethlehem University (honor list), also participated in a summer school program on entrepreneurship at Antwerp University, Belgium. With a Bachelor\'s degree in Biology from Al-Quds Bard College. Outside their professional endeavors, Rasha has been actively engaged in volunteer work with multiple organizations, organizing volunteer activities, cultural events, theater performances, and alternative tours demonstrates their commitment to community development, cultural exchange, and social awareness.&nbsp;</p><p>Rasha Alkhmour is a dedicated and accomplished professional with a strong background in project coordination and monitoring and evaluation. With extensive experience in the social justice, gender equality, social entrepreneurship, social economy and inclusive business in the Palestinian Territories and cultural heritage preservation. Rasha is currently part of the CCE professional development unit managing multiple programs aimed at capacity building.</p>',NULL,NULL,'https://www.linkedin.com/in/rasha-alkhmour-7780b543/','2023-08-30 12:19:00','2024-05-22 12:06:48','storage/8dc3ab91712bcad0c71c29041c638e6e.jpg'),(9,'Fatima Roumate','President','storage/246d137962a7f759f5dd5b592d897f3f.jpg','<p><strong><em>Morocco</em></strong></p><p>Fatima Roumate, PhD, is a full professor of International Law at the Faculty of Law, Economic and Social Sciences Agdal, Mohammed V University, Rabat, Morocco. Her notable achievements include:</p><ul><li>Founding President of the International Institute of Scientific Research, Marrakech, since 2010.</li><li>Member of the Ad Hoc Expert Group for the Recommendation on the Ethics of Artificial Intelligence, UNESCO, Morocco.</li><li>Member of the Information Ethics Working Group, IFAP, UNESCO, since 2020.</li><li>Member of the Moroccan delegation representing Morocco in intergovernmental negotiations on the Recommendation on the Ethics of Artificial Intelligence, UNESCO.</li><li>Member of the International Telecommunication Union (ITU) Focus Group on AI &amp; Environmental Efficiency (FG-AI4EE).</li><li>Founding Member of AI Talk Initiative Code Explorer.</li><li>Member of the consortium Global AI Network for Social Good [GAIN4SG].</li><li>Founder of the Global Network of AI and International Society [GNAI&amp;IS].</li><li>Former expert in cyber–Former Expert, Cybersecurity and International Cooperation, Council of Europe, as part of the CoE Wiki Cybercrime project from 2014 to 2016.</li><li>As the head of The International Institute of Scientific Research, she was ranked 25th in The Thinkers360 annual leaderboard for the 50 Thought Leading Companies on Artificial Intelligence for 2023 - 50 Thought Leading Companies on Artificial Intelligence 2023 | Thinkers360.</li><li>Her name is cited in the list of the Top 20 Inspirational Women of the African Diaspora Professional Women (ADIPWO) list for 2023. This list recognizes and celebrates outstanding women who have made significant contributions in various industries and are putting Africa on the global map - Fostering prosperity for African women (francinebeleyi.com).</li><li>Her edited book topped the list of the 20 best Books on AI and research of all time, released by BookAuthority at the end of January 2023. - Est Artificial Intelligence Research Books of All Time BookAuthority.</li><li>She has received several awards, such as the Award titled “Iconic leader creating change for a better world,” organized by the Women Economic Forum in The Hague, 2017, and the Award received during the Conference organized by Technopark Casablanca and titled “Moroccan Women, a major player in sustainable and prosperous inclusive development,” March 19, 2022; https://menara.ma/fr/article/le-technopark-met-a-lhonneur-la-femme-marocaine-acteur-majeur-du-</li><li>She is a guest editor of the special issue of the Journal of Social Policy Studies, indexed in SCOPUS and dedicated to AI and social policy. She is a member of several scientific board committees of indexed journals such as Magazine Cátedra Villarreal Posgrado and the International Journal titled Revista Científica de Comunicación Social Bausate, published by the University Jaime Bausate y Meza, Lima, Peru.</li><li>She has published several books and indexed articles in Arabic, French, and English. She has organized numerous training sessions for young teachers, elected women, and entrepreneurs, as well as many international conferences about education, science, and technology.</li><li>She is a speaker at numerous international conferences; one of them was organized at the House of State in Finland.</li><li>She was nominated by the Department of State of the USA to participate in the IVLP International Visitor Leadership Program.</li></ul><p><br></p>',NULL,'https://www.facebook.com/profile.php?id=100000157243930','https://www.linkedin.com/in/fatima-roumate-17193920/','2023-08-30 12:57:09','2024-05-22 12:07:01','storage/d4ae023218d108545d65ee5021a1e6d6.jpg'),(10,'Mohammad Jubran','Associate Professor','storage/357d5704aba7bd08027d262cbc49fb87.jpg','<p><strong><em>Palestine</em></strong></p><p>Dr. Mohammad Jubran is an Associate Professor at the Department of Electrical and Computer Engineering at Birzeit University, Birzeit, Palestine. He has earned the B.S. degree in Electronic Engineering from Al-Quds University, Abu-Dies, Palestine, in 2000, and the M.S. and Ph.D. degrees in Electrical Engineering from the University at Buffalo, The State University of New York, Buffalo, NY, USA in 2005 and 2007, respectively. Dr. Jubran was a Visiting Postdoctoral Research Associate at University College London, London, UK (2017-2018) working on Video Processing, Communication, and Classification using Machine Learning.&nbsp;</p><p>Dr. Jubran research interests are in Artificial Intelligence, Machine Learning, and video communication systems. He published many articles in this area. Dr. Jubran has also led and participated in many local and international projects. He has also served as a trainer and mentor for numerous AI-related projects. Dr. Jubran has received many regional and international awards such as the Distinguished Scholar Award - Arab Fund Program, Fulbright Scholarship, Zamalah Fellowship, and Academic Development Award from Birzeit University.</p>',NULL,NULL,'https://www.linkedin.com/in/mjubran','2023-08-30 13:22:28','2024-05-22 12:07:13','storage/70ba89e4746d0b3fba8ffb229e77fde9.jpg'),(11,'Bouchra Al Halmuni','Program Coordinator & Consultant','storage/b3f8997f259a70e46b565d227187a705.jpg','<p><strong><em>Morocco</em></strong></p><p>Bouchra Al Halmuni is a Digital Entrepreneur, Full-stack Developer, Designer, Mentor, Speaker, Artist, and TechWomen fellow. She is the founder of Boxra, WEBA (Women\'s E-Business Academy) and co-founder of T.A.W (The Amazing Woman).&nbsp;</p><p>As a Digital Entrepreneur, Bouchra launched Boxra, a digital agency that develops cutting-edge digital solutions. She combines her technical expertise and innovative ideas to create impactful products. Her skills as a Full-stack Developer and Designer ensure that her projects are visually stunning and function seamlessly.</p><p>Bouchra actively engages in mentoring programs, serving as a Women TechMakers Ambassador and a facilitator for the #IamRemarkable initiative. She empowers aspiring professionals, especially women in tech, to embrace their achievements and overcome self-doubt.&nbsp;</p><p>Beyond tech, Bouchra is a talented artist who uses her work to inspire conversations about society and culture. She is participating in the TechWomen program, connecting with professionals worldwide and broadening her perspectives.</p><p>Committed to her community, Bouchra serves as a paramedic in the Moroccan Red Cross, providing vital medical assistance. Through T.A.W, she strives to bridge the gender gap in tech by empowering women with skills and resources.</p><p>Bouchra Al Halmuni\'s passion for technology, entrepreneurship, mentorship, art, and social impact has made her a respected and influential figure. Her diverse range of skills and unwavering dedication exemplify her commitment to shaping a better future in the tech industry and beyond.</p>','https://twitter.com/al_halmuni','https://www.facebook.com/bouchra.alhalmuni/','https://www.linkedin.com/in/bouchra-al-halmuni/','2023-08-30 13:44:45','2024-05-22 12:08:23','storage/06c2fce4b2db968f30c02e9c2e54bffc.jpg'),(12,'Khadiga Hassan','Researcher','storage/c9b08e5ca75de96c0322eaf8bbde6ca0.jpg','<p><strong><em>Egypt</em></strong></p><p>Khadiga Hassan completed her Undergraduate studies at Suffolk University in Boston, Massachusetts with a Bachelor of Science in Economics with Honors. Upon graduating, she worked as an International Market Research Assistant at the Massachusetts Export Center located in Boston. She moved back to Cairo and joined Access to Knowledge for Development Center (A2K4D) at the American University in Cairo as a researcher in 2020. Since then, Hassan has been engaging in empirical, bottom-up, policy-oriented research on the different intersections related to technology and inclusive development; digital economy, platform economy, the future of work, and issues of Artificial Inclusion (AI), with a focus gender and opportunities for youth, in the context of Egypt, Africa and the Arab world. She developed an interest in AI ethics, data and AI governance, regulating innovation, inequalities and social science, new work and social protection, and labor economics.&nbsp;</p>','https://twitter.com/Khadiga_Hassan?s=20',NULL,'https://www.linkedin.com/in/khadiga-hassan-118404150/?originalSubdomain=eg','2023-08-30 14:10:29','2024-05-22 12:08:51','storage/23beab652c067d16065dbcc43068797b.jpg'),(13,'Nadine Weheba','Associate Director, Access to Knowledge for Development Center','storage/7492a9be3af040b07fd68f16869fbe34.jpg','<p><strong><em>Egypt</em></strong></p><p>Nadine Weheba is the Associate Director at the Access to Knowledge for Development Center. Her research interests are in the political economy of new technologies, innovation, and development. She is interested in how to make new technologies, such as artificial intelligence, inclusive of women, youth and vulnerable groups in the Middle East and North Africa (MENA). She is engaged in empirical, policy-oriented research on the multifaceted inequalities women and other vulnerable groups face in the region’s digital economy.&nbsp;</p>',NULL,NULL,'https://www.linkedin.com/in/nadine-weheba-19291b43/?originalSubdomain=eg','2023-08-30 14:21:09','2024-05-22 12:09:39','storage/26377d110c0298b80d8ab1d396167fbb.jpg'),(14,'Nada Nassar','Research Assistant','storage/cf582e6cdfe7a9c2549d50bca3c75282.jpg','<p><strong><em>Egypt</em></strong></p><p>Nada Nassar earned her undergraduate degree from The American University in Cairo (AUC) with a Bachelor of Arts in Economics with honors. Nada joined the center as a research assistant and is working on several projects related to AI and gender equality, governing responsible AI and data, and innovation. Her research interests include global and human development, policy, technology, and innovation for development. She aspires to pursue a master\'s degree in developmental economics.&nbsp;</p>',NULL,NULL,'https://www.linkedin.com/in/nada-nassar/','2023-08-30 14:23:04','2024-05-22 12:09:51','storage/958abad5b986e38aeb4c5e2f8b0fb18d.jpg'),(15,'Farah ElBehairy','Senior Researcher','storage/337a772551903247801599731c2d8145.jpg','<p><strong><em>Egypt</em></strong></p><p>Farah is an Interdisciplinary Urban Planner and Researcher. She holds a master\'s degree in Integrated Urbanism and Sustainable Design (IUSD) from Ain Shams University and the University of Stuttgart, Germany. Her master\'s thesis \'\'Knowledge Co-production: An Innovation Model towards Institutionalization for the Case of Cairo - Rethinking the Relationship between Knowledge and Action through the Case of Cairo Urban Initiatives\'\' discussed urban knowledge systems in Egypt. She holds a Bachelor of Science in Architectural Engineering, Urban Planning, and Design from Ain Shams University, Egypt. Farah is interested in working on research on the intersection of knowledge, power, and justice. She is currently working as a senior researcher at the Access to Knowledge for Development Center (A2K4D) at the American University in Cairo.&nbsp;</p><p>Before joining A2K4D, Farah worked on research on knowledge-based urban development, planning education and practice, diversity in the urban planning field from the understudied socioeconomic class perspective, Urban Artificial Intelligence (Urban AI), co-construction of data in smart cities, social &amp; ecological justice in smart city planning (smart justice) in the African continent, as well as journalism for spatial justice through addressing housing-related gender stereotypes in Egyptian journalism. Her co-authored paper ‘’Setting an Agenda for Urban AI Adaptivity in Urban Planning and Architecture E-learning’’ is published by the Journal of Engineering Research (ERJ) as a special issue from the ‘’Visions for Future Cities: Innovations &amp; Environmental Technologies Conference’’. At A2K4D, She is currently working on the responsible governance of artificial intelligence and data for development towards just and inclusive knowledge, data, and AI in the Middle East and North Africa (MENA) region. Farah was also a speaker at the AfricAI Conference 2023 in Kigali, Rwanda, co-organized by GIZ FAIR Forward, IDRC, and Niyel under the theme “Advancing responsible and open AI ecosystems in Africa’’.</p>',NULL,NULL,'https://www.linkedin.com/in/farah-elbehairy-7462811b5','2023-08-30 14:28:06','2024-05-22 12:10:22','storage/7d79b810bacf9fb29f692bc5c539dc51.jpg'),(16,'Zeina Sleem','Health and Social Policy Researcher and Evidence Lead Specialist ','storage/c2ad9f6d4243f1549876d339be56d0b5.jpg','<p><strong><em>Lebanon</em></strong></p><p>My professional background encompasses a diverse range of skills, including research design and execution, policy analysis, advocacy, and effective collaboration within multi-disciplinary teams. With a keen ability to deliver evidence-based and contextually tailored policy options, I have consistently provided valuable insights to stakeholders across various sectors.</p>','https://twitter.com/zeinasleem11',NULL,'https://lb.linkedin.com/in/zeina-sleem-6941371b6','2023-08-30 14:32:59','2024-05-22 12:10:36','storage/17b884895e65efed1525d821954d75a0.jpg'),(17,'Meriem Ben Tarjem','Executive Director','storage/0e921e9fee4f1402de6de4299654078e.jpg','<p><strong><em>Tunisia</em></strong></p><p>Meriem Ben Tarjem is a statistician, she has gained extensive experience in the field of risk calculation by working for several years in the insurance sector. In 2022, she made a deliberate shift to channel her expertise towards projects that merge the domains of data and public policy. Her primary focus now lies in developing statistical tools for problem-solving within the field of social sciences.</p>',NULL,NULL,NULL,'2023-08-30 14:35:59','2024-05-22 12:10:49','storage/082a4aee6d0adf2e5fb6b5eb7be20b2b.jpg'),(18,'Ahmed Abu Shaban','Dean and Associate Professor in Agricultural Economics','storage/c92cef04380e0fc60a868dc35c62ea8c.jpg','<p><strong><em>Palestine</em></strong></p><p>With over 15 years in academia across Palestinian National universities, esteemed USA, and German institutions, my passion lies in shaping future leaders across diverse disciplines. I\'ve delved into food security, market system development, rural sociology, and comprehensive social research methodologies encompassing quantitative and qualitative approaches. Additionally, my expertise spans farming systems, agricultural economics, farm management, and managerial economics.</p><p>As the dean of Agriculture and Environment at Al Azhar University Gaza, my leadership highlighted a pioneering rural development program aimed at analyzing agricultural value chain gaps. This initiative sought to uplift marginalized farmers, enhancing their market participation amidst economic adversities.</p><p>A pivotal aspect of my commitment lies in spearheading Green Economy Initiatives, particularly in designing circular economy programs. These initiatives harmonize sustainable economic models with market development, fostering both economic growth and environmental sustainability.</p><p>Concurrently, my research focuses on Food Security and Sustainable Environment, targeting crucial gaps and barriers within these systems. The aim is to empower marginalized groups and facilitate their increased participation in markets, thereby fostering economic empowerment.</p><p>One of my prominent research themes involves leveraging technology and data to optimize food security in Gaza. In collaboration with institutions like The Access to Knowledge for Development Center at the American University in Cairo and four Middle East universities, this study explores AI opportunities, barriers, and recommendations for sustainable enhancement. Financial support from the International Development Research Centre, Ottawa, Canada, bolsters this endeavor.</p><p>The fusion of my expertise in Market System Development with dedicated research in sustainability and food security enables the strategic design of impactful programs. These initiatives empower vulnerable populations and contribute to sustainable economic growth within communities.</p><p>My advocacy for Circular Economy and Sustainable Market Practices underscores a progressive outlook, advocating for eco-friendly models prioritizing environmental preservation alongside fostering economic growth.</p><p>This holistic approach integrates market insights into sustainable strategies, emphasizing the pivotal role of understanding market systems for achieving economic growth, environmental sustainability, and food security.&nbsp;</p>',NULL,NULL,NULL,'2024-02-03 06:18:43','2024-05-22 12:11:06','storage/ccba784b24a309efac46612c8349be8b.jpg'),(19,'Malak Altaeb','Independent Consultant and Researcher','storage/be2e5fd3be28e542607de0b051b3d72b.jpg','<p><strong><em>Libya - France</em></strong></p><p>Malak Altaeb is an independent consultant, writer, and researcher from Libya based in Paris, France. She is an Environmental Policy master’s graduate from Sciences Po in Paris, with a bachelor’s degree in Chemical Engineering from the University of Tripoli, Libya. She is a non-resident fellow with the Tahrir Institute for Middle East Policy (TIMEP) 2022-23 cohort, working on food security in North Africa. Malak is a member of the World Youth Parliament for Water – Research group and the Groundwater Youth Network (GWYN).</p><p>She previously worked as an intern with the Syrian Centre for Media and Freedom of Expression (SCM) in Paris from July to December 2020. Since her graduation in 2020, she has focused on environmental policy in Libya from a policy analysis lens, tackling different topics linked to the environment in Libya and the connections/learnings from other MENA countries, especially Egypt and Tunisia.</p><p>She is a graduate of the North African Policy Initiative’s Young Policy Leaders Program, during which she researched and wrote a policy paper on local agribusiness development in Tripoli, Libya. She also co-authored a policy paper on renewable energy in Libya published on the Policy Corner and researched a paper on water politics in Libya with the Arab Reform Initiative. In addition, she contributed two papers to ISPI - Istituto per gli Studi di Politica Internazionale. She addressed in a recent commentary piece Libya\'s natural resources tackling energy, water, and food security under the impact of the Russia-Ukraine war. She also contributed to the Libya Dossier: Libya between Chaos &amp; Hope, addressing Libya’s environmental challenges due to its political and economic instability.&nbsp;</p><p>She won second in the Centre for Mediterranean Integration (CMI) Marseille’s water heroes contest and participated in the E-Hackathon on Water and Climate Change Entrepreneurship with CMI and CEWAS Middle East. She has also taken part in Konrad Adenauer Stiftung’s (KAS) water journalism academy workshop and participated as a speaker in a panel discussion about ‘’Solution-driven Water Journalism.” Along with other water professionals from the region, Altaeb worked with CEWAS Middle East to design and implement a media campaign for a water-solution based start-up called SOLVillion in Jordan.</p>','https://twitter.com/MalakLibya1',NULL,'https://www.linkedin.com/in/malakali/','2024-02-03 07:31:31','2024-05-22 12:11:29','storage/775a3c5cdcd3fe6e8e70a89b772dc9f7.jpg'),(20,'Nagham ElHoussamy','Associate Director for Research, Middle East and Africa, A2K4D','storage/6cbc95e094f3127dc185e59ce797eedb.jpg','<p><strong><em>Egypt</em></strong></p><p>Nagham ElHoussamy is working on research on the intersection of knowledge, technology, entrepreneurship and development. She joined the A2K4D in June 2012, serving as the North Africa Hub coordinator for the Open African Innovation Research Partnership (Open AIR).</p><p>Prior to joining A2K4D, Nagham was an Economic Researcher in the Macro-Fiscal Policy Unit at the Egyptian Ministry of Finance. She interned at the ICT Policies Unit of the United Nations Economic and Social Commission for West Asia in Beirut. Nagham graduated from The American University in Cairo with an MA in economics in international development and a BA in political science, specializing in international law and International relations, with a minor in economics.</p>','https://twitter.com/nelhoussamy',NULL,'https://www.linkedin.com/in/nagham-el-houssamy-/','2024-02-03 07:58:29','2024-05-22 12:11:43','storage/edf0ade94223e2214df917cefda39920.jpg'),(21,'Nicolas Gholam','Rural/Sustainable Development Practitioner & Researcher','storage/7356a66c96ce70491bcd44ad810b2e09.jpg','<p><strong><em>Lebanon</em></strong></p><p>Nicolas Gholam is a Rural Development Practitioner and Researcher, with a passion for social innovation in times of crises, and local small-holders\' access to market. He is the founder of Mawsam Beirut SARL, a distribution company for local small-scale producers. He has previously managed the Souk El Tayeb Farmers\' Market, led the outreach and operation of the Environment and Sustainable Development Unit at the American University of Beirut, and served as a coordinator for the Strong Cities Network\'s PVE Program in Lebanon, Jordan, and Iraq. He is currently a fellow with the European Institute of Innovation &amp; Technology (EIT Food) and is working as an Economic Growth Consultant with several entities.</p>',NULL,NULL,'https://www.linkedin.com/in/nicholasgholam12345/','2024-02-03 08:03:21','2024-05-22 12:11:53','storage/8a6fbed78afd52ad5d28e76bdb0dbb84.jpg'),(22,'Shahed Nabeel Al-khateeb','Research Assistant at Yarmouk University and Founder of World of Plant','storage/ddbc3dbf187d544cd018389e8c66947c.jpg','<p><strong><em>Jordan</em></strong></p><p>Shahed Al-Khateeb is an expert in the field of artificial intelligence. She earned her bachelor\'s degree in computer science and a master\'s degree in artificial intelligence from Yarmouk University. Shahed is passionate about education and has worked as a teacher in the computer science department. Currently, she holds the position of research assistant at Yarmouk University.</p><p>In 2023, Shahad earned the Arab ITAS 2023 Award in Doha, Qatar, from the University of Doha for Science and Technology. Recognized during the International Conference on Innovation and Technological Advances for Sustainability, the accolade applauds Shahad\'s outstanding use of artificial intelligence for innovative solutions in the agricultural sector.</p><p>In addition to her academic pursuits, Shahed is an entrepreneur and the founder of World of Plant, a startup company with a mission to revolutionize the agricultural sector in Jordan using innovative applications of artificial intelligence. Her startup focuses on implementing cutting-edge solutions to address challenges in agriculture, highlighting her dedication to leveraging technology for positive societal and economic impact.</p><p>Shahed\'s research interests cover a wide range of topics, including government data analysis, computer vision, and text analysis in both Arabic and English. She is actively involved in developing predictive models, showcasing her commitment to exploring the potential of artificial intelligence across diverse fields.</p>',NULL,'https://www.facebook.com/ShahedAlkhateeb95/','https://www.linkedin.com/in/shahd-alkhateib1995/','2024-02-03 08:20:59','2024-05-22 12:12:04','storage/6b07649c83dcdf6d3c56f87197385094.jpg'),(23,'Nagla Rizk','Professor of Economics and Founding Director','storage/42bcf157481dcc6adf0b80eb6b1da122.jpg','<p><strong><em>Egypt</em></strong></p><p>Nagla’s area of research, teaching and advocacy is the economics of knowledge, technology and development, with focus on governance of data, responsible Artificial Intelligence, fair work in the platform economy, innovation, gender and inclusion in Egypt, the Middle East and North Africa (MENA). Her research is multidisciplinary in nature and aims at offering academic contribution to an area of interest that is novel to Egypt and the region, while contributing to global scholarship and actively presenting the voice of developing countries in global conversations.&nbsp; In her work as founding director of the Access to Knowledge for Development Center (A2K4D), Nagla is engaged with regional and international partners working on policy-oriented research that focuses on the developmental perspective of knowledge in general and knowledge governance in particular. Given the multidisciplinary nature of her area of interest, her teaching spans academic specializations and speaks to students of diverse fields. Her record also includes active citizenry within AUC through membership in numerous committees and engagement in various administrative capacities, currently as Center Director, and previously as Associate Dean for Graduate Studies and Research at the School of Business and Chair of the Department of Economics.&nbsp;</p><p>Nagla founded the <a href=\"https://idl-bnc-idrc.dspacedirect.org/bitstream/handle/10625/57601/IDL-57601.pdf?sequence=2&amp;isAllowed=y\">Open Data for Development Node for the Middle East and North Africa</a> and leads the <a href=\"https://aplusalliance.org/about-fair/\">Feminist AI Research (f&lt;a+i&gt;r)network’s</a> MENA hub, <a href=\"https://openair.africa/\">Open African Innovation Research Partnership (Open AIR)</a>’s North Africa hub, and the <a href=\"https://fair.work/en/fw/homepage/\">Fairwork</a> Egypt team, in partnership with Oxford Internet Institute. She is a Faculty Associate at Harvard’s <a href=\"https://cyber.harvard.edu/\">Berkman Klein Center for Internet and Society</a>, Affiliate Faculty at Harvard Law School’s <a href=\"https://cyber.harvard.edu/teaching/copyrightx\">CopyrightX</a> course and an Affiliated Fellow of Yale Law School’s <a href=\"https://law.yale.edu/isp\">Information Society Project</a>.&nbsp; She is Associate Member at the University of Ottawa’s <a href=\"https://techlaw.uottawa.ca/\">Centre for Law, Technology and Society</a>.&nbsp;</p><p>Examples are the <a href=\"https://www.weforum.org/communities/global-future-councils\">World Economic Forum’s Global Future Councils</a>, Expert Advisory Committee of the <a href=\"https://www.responsibleaiindex.org/\">Global Index on Responsible Artificial Intelligence</a>, <a href=\"https://parispeaceforum.org/en/initiatives/initiate-digital-rights-in-society/\">Paris Peace Forum Digital Rights in Society</a> Working Group on Algorithmic Governance, and the <a href=\"https://gpai.ai/\">Global Partnership on AI (GPAI)</a>’s <a href=\"https://gpai.ai/projects/data-governance/#:~:text=The%20Working%20Group%20aims%20to,innovation%2C%20economic%20growth%2C%20and%20societal\">Data Governance Working Group</a>. She received her PhD in economics from <a href=\"https://www.mcmaster.ca/\">McMaster University</a> in Canada, and her MA and BA in economics from AUC.</p>',NULL,NULL,'https://www.linkedin.com/in/naglarizk/','2024-02-03 18:06:23','2024-05-22 12:12:15','storage/cc072f24c35fc0d06dbd57499aa8bbcb.jpg'),(24,'Myriam Raymond','Enseignante Chercheuse & Co-Responsable Master 2 Pricing et Revenue Management','storage/101bf923a2f7b205ec0af8527a6501e2.jpg','<p><strong><em>Egypt - France</em></strong></p><p>Myriam Raymond is a researcher at <a href=\"https://granem.univ-angers.fr/fr/index.html\">GRANEM (Groupe de Recherche ANgevin en Économie et Management)</a>.&nbsp;</p><p>She is also involved in interdisciplinary research at <a href=\"https://diplab.eu/\">DiPLab (Digital Platform Labor)</a>, with a particular focus on the <a href=\"https://diplab.eu/projects-2/hush-the-human-supply-chain-behind-smart-technologies/\">HuSh project (The Human Supply Chain Behind Smart Technologies)</a>, which explores the human supply chain behind smart technologies.&nbsp;</p><p>With a dynamic career between scientific research and management consultancy, Myriam Raymond has consolidated her expertise through various contributions and large-scale IS research projects, in key areas such as FinTech, innovation and artificial intelligence. Her research interests also include Digital Platforms, Algorithmic Management and business process outsourcing (BPO).&nbsp;</p>',NULL,NULL,'https://www.linkedin.com/in/myriam-raymond-iskander/','2024-02-29 09:47:10','2024-05-22 12:13:08','storage/6fc52a795d8a908994a7bc8d35a41288.jpg'),(25,'Alia Shaddad','Senior Researcher','storage/732ca1244ca57cea8fc81e000a5211c2.jpg','<p><strong><em>Egypt</em></strong></p><p>Alia Shaddad is an anthropologist based in Cairo, and a Senior Researcher at the Access to Knowledge for Development Center. She is also an Adjunct Lecturer of Sociology and Anthropology at The American University in Cairo (AUC) . She obtained her Master of Arts in sociology-anthropology from AUC in 2021. Shaddad holds a Bachelor of Arts in honors political science with minors in economics and anthropology from AUC. She believes in the necessity of interdisciplinarity and often works with different media to express her work. Her work often explores space, time, subjectivity, relationships, alternativeness, affect, and potentialities. She has more recently explored these themes within the context of tech, data, and AI in Egypt and the Middle East and North Africa region.</p>','https://twitter.com/alia_shaddad',NULL,'https://www.linkedin.com/in/aliashaddad/','2024-03-25 11:27:09','2024-05-22 12:13:23','storage/0dda8e96c09dc0a72c28723bc005b214.jpg'),(27,'Ranwa Yehia','Co-Founder/Chairperson Arab Digital Expression Foundation (Cairo, Beirut), Executive Director Arab Digital Expression Berlin e.V ','storage/cfe9f361ae2968bfd80995e8603cc268.jpg','<p><strong><em>Egypt</em></strong></p><p>Ranwa Yehia is the co-founder and chairperson of the <a href=\"https://adef.xyz/\">Arab Digital Expression Foundation (ADEF)</a>, which started in 2005 with a mission to explore and develop alternative education methodologies and knowledge production for and by Arab youth, using open source concepts and tools. A key project she conceived with ADEF is the Arab Digital Expression Camps, an annual experiential co-learning camp for Arab youth, developed and implemented in collaboration with young techies, artists, journalists, and researchers in the region. ADEF currently boasts four major programs working across Egypt, the Arab region and with Arab diaspora. ADEF has impacted thousands of Arab youth, empowering them with criticality, knowledge production and creative expression. Her most recent project at ADEF is establishing an Inclusion Unit in 2018. As a result, ADEF is now able to welcome neurodiverse teens and young adults (autism, ADHD, etc) into ADEF\' various programmes. Before moving on to a career versed in methodologies of youth work and organization, Ranwa’s trajectory with knowledge production was centered on journalism and research, where she spent 15 years covering the Arab region for different regional and international media outlets.</p><p>Ranwayehia@arabdigitalexpression.org</p><h3><strong>Publications:&nbsp;</strong></h3><ul><li>Hundreds of new, political analysis and features in The Daily Star, LA Times, Al-Hayat (London), DPA.</li><li><a href=\" https://yplus.ps/wp-content/uploads/2021/01/Parsons-Nigel-The-Politics-of-the-Palestinian-Authority-From-Oslo-to-Al-Aqsa.pdf\">MA Research Paper (quoted in Politics and Palestinian Authority)</a></li></ul><p><em>Interviewed about impact of ADEF in:</em></p><ul><li><a href=\"https://papers.ssrn.com/sol3/Delivery.cfm/SSRN_ID1729370_code16031.pdf?abstractid=1729370&amp;mirid=1\">Access to Knowledge in Egypt&nbsp;</a></li><li><a href=\"https://www.sup.org/books/title/?id=27100\">Arab Glitch</a></li></ul>','https://twitter.com/ranwayehia?lang=en',NULL,'https://www.linkedin.com/in/ranwayehia?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app','2024-04-29 09:50:47','2024-05-22 12:13:47','storage/ebcc98aef4caae90b93982d34773fa6b.jpg'),(28,'Seham Elmrayed','Assistant Professor at the Institute of Global Health and Human Ecology, American University in Cairo','storage/9e87dd23abbb1fdc795fb13e5db5cbc1.jpg','<p><strong><em>Egypt</em></strong></p><p><a href=\"https://www.aucegypt.edu/fac/seham-elmrayed\">Seham Elmrayed</a>, a pediatric epidemiologist at the Institute of Global Health and Human Ecology (IGHHE) at The American University in Cairo (AUC), concentrates her research on child growth, as well as maternal and child nutrition. Her previous work in Canada involved analyzing national public health data, emphasizing longitudinal studies examining growth and nutritional outcomes in children under five years old.</p><p>seham.elmrayed@aucegypt.edu</p>',NULL,NULL,'https://www.linkedin.com/in/seham-elmrayed-369279300/','2024-04-29 09:59:12','2024-05-22 12:13:57','storage/8e2a50b47e5571d983abf0031e9d09d2.jpg'),(29,'Nahed Azab','Adjunct Assistant Professor of MIS, The American University in Cairo','storage/ad44c57d9a38ac815b437302719823a4.jpg','<p><strong><em>Egypt</em></strong></p><p>Dr. Nahed Azab is an IT consultant, mentor, and professor. She plays an active role in planning and updating the curriculum, compiling and editing the material and coursework, and teaching several IT undergraduate and postgraduate courses at the American University in Cairo. In particular, Dr. Azab focuses on Electronic Commerce, Electronic Marketing, Management Information Systems, and Business Intelligence. She obtained her PhD from the School of Engineering and Information Sciences - Middlesex University, London (July 2010). Dr. Azab obtained her MSc. In Business Information Technology, School of Computing Sciences - Middlesex University, London (July 2002). Her career path encompassed software programming, analysis and design, computer center management, software instruction, and general IT consultancy with public and private entities such as the Ministry of State for Administrative Development and McKinsey &amp; Company. Dr. Azab is a committee member in several journals, books, and conferences. She also presented a number of academic papers in journals, books, and conferences.</p><p>nazab@aucegypt.edu</p><h3><strong>Publications:</strong></h3><p><strong><em>Refereed Journals</em></strong></p><ul><li>Ali, M., Gomes, L., Azab, N., Souza, J., Sorour, K. and Kimura, H. (2023). “Panic Buying and Fake News in Urban vs. Rural UK: A Case Study of Twitter During COVID-19”. Technological Forecasting and Social Change, special issue: Social Customer Journey — Behavioural and Social Implications of Digitally Disruptive Environment</li><li>Ali, M. Azab, N., and Sorour, K. (2019). “Integration v. Polarization Amongst Social Media Users: Perspectives through Social Capital Theory on The Recent Egyptian Political Landscape”. Technological Forecasting and Social Change, special issue: Acculturation in the Social Media: a myth or reality? Analysing social media led integration and polarisation.</li><li>Themist, M., Azab, N., Kamal, M. Ali, M., and Morabito, V. (2012). “Location-Based Services for Public Policy Making: The Direct and Indirect Way to e-Participation”. Information Systems Management, 29(4): 269-283.</li><li>Azab, N. (2012). “Challenges and Opportunities of Using the Internet to Realize Democracy in Egypt“. Journal of North African Research in Business, 2012 (547105).</li><li>Azab, N. (2012). “The Role of the Internet in Shaping the Political Process in Egypt”. The International Journal of ePolitics (IJEP), 3(2), 30-49.</li><li>Azab, N. (2009). “Assessing E-Government Readiness of Public Organizations”. Communications of the IBIMA, 8(13).</li><li>Azab, N., Kamel, S., Dafoulas, G. (2009). “A Suggested Framework for Assessing E-Government Readiness in Egypt (Case of a Public Organization)”. Electronic Journal of E-Government (EJEG), 7(1):11-28.&nbsp;</li></ul><p><strong><em>Books</em></strong></p><ul><li>Azab, N. (2013) Ed.. “Cases on Web 2.0 in Developing Countries: Studies on Implementation, Application and Use”. IGI Global, PA, USA.</li><li>Azab, N. (2013). \"Assessing E-Government Readiness of Egyptian Public Organisations”.&nbsp; LAP LAMBERT Academic Publishing, ISBN 978-3-8465-8836-9.</li></ul><p><strong><em>Book Chapters</em></strong></p><ul><li>Azab, N., Farzali, E. Zaher, O., and Sayed, H. (2014). “Government 2.0:&nbsp; A Change Towards Citizen Participation in Arab Countries”. Chapter in “Case Studies in E-Government 2.0: Changing the Citizen Relationship”. Springer&nbsp; NY, 2014.</li><li>Azab, N. and AbdelSalam, H., and Gamal, S. (2013). “Use of Web 2.0 Collaboration Technologies in Egyptian Public Universities: An Exploratory Study”. Chapter in “E-Government Implementation and Practice in Developing Countries”. IGI Global, PA, USA.&nbsp;</li><li>Azab, N. and Khalifa, N. (2013).&nbsp; “Web 2.0 and Opportunities for Entrepreneurs: How Egyptian Entrepreneurs Perceive and Exploit Web 2.0 Technologies”. Chapter in “Cases on Web 2.0 in Developing Countries: Studies on Implementation, Application and Use”. IGI Global, PA, USA.</li><li>Azab, N. (2010). “Assessing E-Government Readiness in Egypt - Comparison between Two Public Organizations”. Chapter in “E-Strategies for Technological Diffusion and Adoption: National ICT Approaches for Socioeconomic Development”. IGI Global, PA, USA.&nbsp;</li><li>Azab, N. (June 2005). “Assessing Job Seekers’ Acceptance of On-Line Recruitment in Egypt”. Chapter in a book entitled “E-Business in Developing Countries: Opportunities and Challenges\", Idea Group Publishing, PA, USA.</li><li>Azab, N. and Wahba, K. (2003). “A Framework for Knowledge Management Adoption in an Egyptian Steel Company”. Chapter in a book entitled “Information Technology and Organizations: Trends, Issues, Challenges and Solutions”. Idea Group Inc., PA, USA.</li></ul><p><strong><em>Refereed Proceedings</em></strong></p><ul><li>Azab, N. and ElSherif, M. (2024). “A Framework for the Adoption and Use of Information and Communication Technology for Empowering Women Entrepreneurs”. To be submitted to the 2024 International Conference on Information Resources Management (CONF-IRM2024), May 26-28, 2024.</li><li>Azab, N. and ElSherif, M. (2023). “Measuring Trust in Government Amid COVID-19 Pandemic and the Russian-Ukraine War”. 8th International Congress on Information and Communication Technology (ICICT 2023), February 20-23, 2023.</li><li>ElSherif, M. and Azab, N. (2019). “A Framework to Measure E-Participation Level of Government Social Media Accounts”. 9th International Conference on Information Systems and Technologies (ICIST\'2019), March 24-26, 2019.</li><li>Azab, N. and ElSherif, M. (2018). “A Framework for Using Data Analytics to Measure Trust in Government through the Social Capital Generated over Governmental Social Media Platforms”.&nbsp; The 19th Annual International Conference on Digital Government Research (dgo.2018), May 30th - June 1st, 2018.</li><li>Rateb, D., Hosni, H. Heikal, F., and Azab, N. (2018). “Using Immersive Virtual Reality in Ancient Egypt’s Giza Plateau”. Middle East and North Africa Conference for Information Systems (Menacis2018), March 22d and 23d, 2018.</li><li>Azab, N., Farzali, E. Zaher, O., and Sayed, H. (2013). “Web 2.0 Technology applications for E-Participation in Arab Countries”. The 21st European Conference on Information Systems (ECIS2013), Pre-ECIS Workshop: E-Government 2.0: Case studies and Experience Reports, Utrecht, The Netherlands.</li><li>Azab, N. (2012). “Use of the Internet in Egypt – A Tool to Reach or to Alter Democracy?”. The International Business Information Management Conference (18th IBIMA): Conference on Innovation and Sustainable Economic Competitive Advantage - From Regional Development to World Economies, May 9-10, 2012, Istanbul, Turkey.</li><li>Azab, N. (2012). \"Business Opportunities Created by the Internet: A Study of Internet Entrepreneurs in Egypt\". 2012 AUC Research Conference: Entrepreneurship and Innovation: Shaping the Future of Egypt, April 17-19, 2012, Cairo, Egypt.</li><li>Khalifa, N., Khalifa, N., AbdelGhani, M., and Azab, N. (2012). “Vendor- Managed Inventory in Developing Countries: Implications and Complications”. 6th International Conference on Operations and Supply Chain Management (ICOSCM) &amp; 9th International Conference on Supply Chain Management and Information Systems (SCMIS), July 14-17, 2012, Xi’an, China.</li><li>Khalifa, N. and Azab, N. (2012). “ERP in Developing Countries: Real or Hollow Systems?”. IADIS International Conference 2012, Berlin, Germany, 10-12 March 2012.</li><li>Azab, N. (2012). \"Role of processes in Electronic Government (Case of Egypt)”. The 3rd International Conference on Society and Information Technologies: ICSIT 2012, Orlando, Florida, 25-28 March 2012.</li><li>Azab, N. (2011). “Use of Information Systems and Electronic Commerce Success Models to Assess Electronic Government Projects”. Proceedings of the 17th International Conference on Information Systems Analysis and Synthesis (ISAS 2011), Orlando, Florida, USA, 27-30 March 2011.&nbsp;</li><li>Azab, N. (2009). “Assessing eGovernment Readiness of Public Organizations”. Proceedings of the 11th International Business Information Management Association Conference (IBIMA 2009), Cairo, Egypt, 4-6 January 2009.&nbsp;</li><li>Azab, N., Ali, M., Dafoulas, G. (December, 2006). “Incorporating CRM in E-Government: Case of Egypt”. IADIS International Conference, E-Commerce 2006, Barcelona, Spain.</li><li>Azab, N. (2005), “Investigating IT-Business Alignment in an Egyptian Medium-Sized Enterprise”. European and Mediterranean Conference on Information Systems (EMCIS 2005), Cairo, Egypt.</li><li>Azab, N. (2004). “Assessing E-Government Readiness in Egypt: Comparative Analysis with United Kingdom (UK), and United Arab Emirates (UAE)”. Conference of Information Science, Technology and Management (CISTM2004), Alexandria, Egypt.</li><li>Azab, N. &amp; Wahba, K. (May 2003). “A Framework for Knowledge Management Adoption in an Egyptian Steel Company”. Information Resources Management Association International Conference (IRMA 2003), Philadelphia, Pennsylvania, USA.</li></ul><p><strong><em>Case Studies</em></strong></p><ul><li>Azab, N., Mekkawy, A. (2016). “Ariika: A Successful Implementation of Information and Communication Technology by Egyptian Entrepreneurs”. Emerald Emerging Markets Case Studies, 6(3): 1-27.&nbsp;</li><li>Azab, N., ElSheikh, Y., Moharram, A., Ibrahim, B., and Yehia, N. (2016). “A Strategic Use of Technology: Case of Vodafone Egypt”. Emerald Emerging Markets Case Studies, 6(3): 1-16.</li><li>Azab, N. (2012). “The Egyptian Tax Authority – Transforming Relationship with Taxpayers through Electronic Government”. Case study in “Management Information Systems: Arab World Edition”, Laudon &amp; Laudon. Pearson.</li></ul>',NULL,NULL,'https://www.linkedin.com/in/nahed-azab-phd-14445420/','2024-04-29 10:06:11','2024-05-22 12:14:18','storage/09c2fd2fb0d8c80d89bf6cbe899c4926.jpg'),(30,'Ayman Ismail','Associate Professor and Abdul Latif Jameel Endowed Chair of Entrepreneurship','storage/cd665fe15d40ba4a226c2b6323602bd4.jpg','<p><strong><em>Egypt</em></strong></p><p><a href=\"https://www.aucegypt.edu/fac/ayman-ismail\">Ayman Ismail</a> is the Abdul Latif Jameel Endowed Chair of Entrepreneurship and Associate Professor at AUC School of Business and the founding director of AUC Venture Lab and AUC Innovation Hub. He is also the Chairman of the Board of Egypt Ventures and PayMob, and a co-founder, angel investor or board member in several fast-growing tech-startups and financial institutions.&nbsp; Previously, he was a research fellow at Harvard Kennedy School, a consultant in McKinsey &amp; Company’s New York office and the World Bank, a co-founder and managing partner at Enovio Consulting, and a Young Global Leader (YGL) at the World Economic Forum (WEF). He received his PhD in International Economic Development from MIT.</p><p>aymanism@aucegypt.edu</p>',NULL,NULL,'https://www.linkedin.com/in/aymanism/','2024-05-02 18:33:03','2024-05-22 12:14:27','storage/9eaf60836c53196931917c3817477862.jpg'),(31,'Ahmed Fouad Abaza','CEO, Synapse Analytics','storage/0ba72618a9c4fd45fc8536131ea2d520.jpg','<p><strong><em>Egypt</em></strong></p><p>Ahmed is the CEO of <a href=\"https://www.synapse-analytics.io/\">Synapse Analytics</a>. Ahmed’s experience spans across IT, Industrial Automation, AI, Data Science, and&nbsp; Consulting. At the helm of a dynamic team comprising more than 50 Engineers, Consultants, Product Managers, and Industry Experts, Ahmed and his team are building cutting-edge AI products to accelerate AI into the forefront of enterprise and government sectors, igniting innovation and progress on a grand scale. He is also a member of the esteemed National Technical Committee for AI in Egypt, that works in shaping the AI landscape at a national level.</p><p>aabaza@synapse-analytics.io</p><p><strong>Relevant publications can be found on:</strong> <a href=\"http://synapse-analytics.io/techqualia\">Synapse-analytics.io/techqualia</a></p>',NULL,NULL,'https://ae.linkedin.com/in/ahmed-fouad-abaza','2024-05-22 11:50:27','2024-05-22 12:14:33','storage/56ef76ce8fbcd8731b29809370510073.jpg'),(32,'Mennatullah Hendawy','Assistant Professor at Ain Shams University, Urban Planning & Design','storage/71199a1b0bf7baea90b764ced12ee4b3.jpg','<p><strong><em>Egypt&nbsp;</em></strong></p><p><a href=\"https://sites.google.com/view/mennatullah-hendawy\">Dr. Mennatullah Hendawy</a> is an interdisciplinary urban planner working at the intersections of cities, media, and technology toward equity and sustainability. She is an assistant professor at Ain Shams University in Cairo, Egypt, and is also affiliated with&nbsp; Impact Circles e.V., Berlin. Hendawy received her Ph.D. in 2021 from the Faculty of Planning, Building Environment at TU Berlin in Germany, graded summa cum laude. In her dissertation, she explored the mediatization of urban development in Cairo as a local yet global case. In 2015, Hendawy completed an MSc in Integrated Urbanism and Sustainable Design from Stuttgart University, focusing on urban policies. She holds a Bachelor of Science in Architectural Engineering from Ain Shams University in Cairo, Department of Urban Planning and Design, class of 2012.&nbsp;</p><p>Hendawy is one of the founding members of Cairo Urban AI, a project exploring the potential of using artificial intelligence to develop just and sustainable cities. Hendawy was the principal investigator of the Urban AI MOOC, which is part of the African Cities Lab initiative, funded by the Swiss State Secretariat for Economic Affairs.</p><p>mennatullah.hendawy@impactcircles.org</p><p><strong>Publications can be found here: </strong><a href=\"https://scholar.google.com/citations?user=OGPZ4kUAAAAJ&amp;hl=en\">https://scholar.google.com/citations?user=OGPZ4kUAAAAJ&amp;hl=en</a></p>',NULL,NULL,'https://www.linkedin.com/in/mhendawy/?msgControlName=reply_to_sender&msgConversationId=6537451979650678784&msgOverlay=true','2024-05-22 11:59:06','2024-05-22 12:14:43','storage/bb3fabce5f8846c8448a1bd766bce0ff.jpg'),(33,'Christophe Zoghbi','Founder & CEO, ZAKA','storage/23f5917386e532d2b6308fe27972c16e.jpg','<p><strong><em>Lebanon</em></strong></p><p>Christophe is an accomplished software engineer with extensive experience spanning over 14 years in various areas of Data Science and Artificial Intelligence.&nbsp; In addition to his technical expertise, he is also a seasoned entrepreneur with a track record of launching and scaling successful ventures.</p><p>christophe@zaka.ai</p>','https://twitter.com/kristoffzoghbi','https://facebook.com/christophe.zoghbi','https://www.linkedin.com/in/christophezoghbi/','2024-05-22 12:05:02','2024-05-22 12:17:08','storage/81a3772a76633e8c08cf1b7078960541.jpg');
