INSERT INTO `gender_ais` VALUES (1,'FEMINIST AI IN MENA – A NEUTRAL TECHNOLOGY?','There are signs of progress in MENA towards the inclusion of female epistemology with the increase in female-led tech startups; FemTech.','storage/aa5fefea6bfca1f87bfdd5711f2f0514.jpg','https://menaobservatory.ai/en/blogs/44','2024-01-04 07:26:50','2024-09-26 00:55:32',1,'feminist_ai'),(2,'Deliberate, inclusive AI policies to empower women in Africa ','In the quest for gender equality, the emergence of artificial intelligence (AI) offers unprecedented opportunities and challenges.','storage/fee7a12cc158bc00e1bd7db78cec9e60.jpg','https://menaobservatory.ai/en/blogs/41','2024-01-04 07:28:50','2024-04-17 11:22:32',0,'none'),(3,'Towards Gender Equality in Egypt’s Digital Economy: An Overview of New Initiatives','Ever wondered if Artificial Intelligence (AI) is truly neutral? Is AI genuinely free from human prejudice? Is the technology impartial?','storage/e92e9225e3810d1058ce0efcc184122e.png','https://menaobservatory.ai/en/blogs/28','2024-01-04 07:29:39','2024-09-26 00:54:40',0,'none');
