INSERT INTO `submitted_works` VALUES (6,'Ayman Batisha','abatisha@gmail.com','01006443210','	Ayman Batisha holds a Ph.D. in Civil Engineering from Cairo University (Egypt, 2001). Dr. Batisha has got his M. Sc. & B.Sc. from the Faculty of Engineering, Cairo University, Egypt. Dr. Batisha has got a Distinction grade in the \"Shared Water Resources Diploma (SWRD)\" that has been held at the Faculty of Engineering, Cairo University.\r\n	Dr. Batisha has completed international training in the field of Environmental Impact Assessment implemented in the National Environmental Protection Agency NEPA, and World Bank, Washington DC, and Sacramento River Watershed, California, in the USA.','forms/1720602621_Dr. Ayman Batisha - CV (maximum 4 pages).docx','forms/1720602621_s41599-023-02146-3.pdf','2024-07-10 09:10:21','2024-07-10 09:10:21');
/*!40000 ALTER TABLE `submitted_works` ENABLE KEYS */;
